      --acento-claro:   #fdf0e0;

      --fuente-titulo:  'Playfair Display', Georgia, serif;
      --fuente-cuerpo:  'Source Sans 3', Helvetica, sans-serif;

      --radio:          8px;
      --radio-lg:       14px;
      --sombra:         0 4px 18px rgba(26,75,110,.12);
      --sombra-lg:      0 8px 32px rgba(26,75,110,.18);
    }

    /* ─── Reset básico ───────────────────────────────────────────── */
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      font-family: var(--fuente-cuerpo);
      color: var(--texto);
      background: var(--arena);
      line-height: 1.65;
      font-size: 16px;
    }

    /* ─── Cabecera ───────────────────────────────────────────────── */
    .cabecera {
      background: var(--azul-mar);
      color: var(--blanco);
      padding: 48px 40px 40px;
      position: relative;
      overflow: hidden;
    }
    .cabecera::before {
      content: '';
      position: absolute;
      inset: 0;
      background: url("data:image/svg+xml,%3Csvg width='80' height='80' viewBox='0 0 80 80' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.04'%3E%3Cpath d='M0 40 Q20 20 40 40 Q60 60 80 40 L80 80 L0 80Z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E") repeat-x bottom;
      pointer-events: none;
    }
    .cabecera-inner { max-width: 860px; margin: 0 auto; position: relative; }

    .etiqueta-ciclo {
      display: inline-block;
      font-family: var(--fuente-cuerpo);
      font-size: 11px;
      font-weight: 600;
      letter-spacing: .12em;
      text-transform: uppercase;
      color: var(--turquesa);
      border: 1px solid var(--turquesa);
      border-radius: 40px;
      padding: 4px 14px;
      margin-bottom: 20px;
    }
    .cabecera h1 {
      font-family: var(--fuente-titulo);
      font-size: clamp(26px, 4vw, 38px);
      font-weight: 700;
      line-height: 1.2;
      margin-bottom: 8px;
    }
    .cabecera-subtitulo {
      font-size: 15px;
      font-style: italic;
      color: rgba(255,255,255,.72);
      margin-bottom: 28px;
    }
    .meta-fila {
      display: flex;
      flex-wrap: wrap;
      gap: 20px;
      font-size: 13px;
      color: rgba(255,255,255,.80);
    }
    .meta-item { display: flex; align-items: center; gap: 7px; }
    .meta-item svg { flex-shrink: 0; opacity: .7; }

    /* ─── Contenido principal ────────────────────────────────────── */
    .contenido { max-width: 860px; margin: 0 auto; padding: 48px 24px 72px; }

    /* Sección genérica */
    .seccion { margin-bottom: 52px; }

    .seccion-titulo {
      font-family: var(--fuente-titulo);
      font-size: 22px;
      color: var(--azul-mar);
      border-bottom: 2px solid var(--arena-oscura);
      padding-bottom: 10px;
      margin-bottom: 22px;
      display: flex;
      align-items: center;
      gap: 10px;
    }
    .seccion-titulo .icono-seccion {
      width: 28px; height: 28px;
      background: var(--azul-mar);
      border-radius: 6px;
      display: flex; align-items: center; justify-content: center;
      flex-shrink: 0;
    }
    .seccion-titulo .icono-seccion svg { color: #fff; }

    p { margin-bottom: 14px; }
    p:last-child { margin-bottom: 0; }

    /* ─── Tarjeta de introducción ────────────────────────────────── */
    .tarjeta-intro {
      background: var(--blanco);
      border-left: 4px solid var(--turquesa);
      border-radius: var(--radio-lg);
      padding: 24px 28px;
      box-shadow: var(--sombra);
      font-size: 15px;
    }

    /* ─── Módulos ────────────────────────────────────────────────── */
    .grid-modulos {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
      gap: 16px;
    }
    .tarjeta-modulo {
      background: var(--blanco);
      border-radius: var(--radio-lg);
      padding: 20px 22px;
      box-shadow: var(--sombra);
      border-top: 3px solid var(--azul-claro);
      transition: transform .15s, box-shadow .15s;
    }
    .tarjeta-modulo:hover { transform: translateY(-3px); box-shadow: var(--sombra-lg); }
    .tarjeta-modulo h3 {
      font-size: 14px;
      font-weight: 600;
