    /* ─── Tabla de tareas ────────────────────────────────────────── */
    .tabla-wrapper {
      overflow-x: auto;
      border-radius: var(--radio-lg);
      box-shadow: var(--sombra);
    }
    table {
      width: 100%;
      border-collapse: collapse;
      background: var(--blanco);
      font-size: 14px;
    }
    thead tr {
      background: var(--azul-mar);
      color: var(--blanco);
    }
    thead th {
      padding: 13px 16px;
      text-align: left;
      font-weight: 600;
      font-size: 12px;
      letter-spacing: .06em;
      text-transform: uppercase;
      white-space: nowrap;
    }
    tbody tr { border-bottom: 1px solid #edf0f3; }
    tbody tr:last-child { border-bottom: none; }
    tbody tr:hover { background: #f5f9fd; }
    tbody td {
      padding: 13px 16px;
      vertical-align: top;
      color: var(--texto);
    }

    /* Columna "Tarea" en negrita */
    tbody td:first-child { font-weight: 600; color: var(--azul-mar); }

    /* Etiqueta de herramienta */
    .tag-herramienta {
      display: inline-block;
      background: var(--acento-claro);
      color: var(--acento);
      border: 1px solid #f0d0a0;
      border-radius: 20px;
      padding: 2px 9px;
      font-size: 12px;
      font-weight: 600;
      white-space: nowrap;
    }

    /* Etiqueta de agrupamiento */
    .tag-grupo {
      display: inline-block;
      background: #e8f4fb;
      color: var(--azul-claro);
      border: 1px solid #c0ddf0;
      border-radius: 20px;
      padding: 2px 9px;
      font-size: 12px;
    }

    /* ─── Tarjetas de instrumentos ───────────────────────────────── */
    .grid-instrumentos {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
      gap: 18px;
    }
    .tarjeta-instrumento {
      background: var(--blanco);
      border-radius: var(--radio-lg);
      padding: 22px 22px 20px;
      box-shadow: var(--sombra);
      display: flex;
      flex-direction: column;
      gap: 10px;
    }
    .instrumento-icono {
      width: 44px; height: 44px;
      border-radius: 12px;
      display: flex; align-items: center; justify-content: center;
    }
    .color-semanal   { background: #dff2ef; }
    .color-diana     { background: #fde8d0; }
    .color-rubrica   { background: #dde8f8; }
    .tarjeta-instrumento h3 {
      font-size: 15px;
      font-weight: 600;
      color: var(--azul-mar);
      line-height: 1.3;
    }
    .instrumento-momento {
      font-size: 12px;
      font-weight: 600;
      text-transform: uppercase;
      letter-spacing: .06em;
      color: var(--texto-suave);
    }
    .instrumento-desc {
      font-size: 13px;
      color: var(--texto-suave);
      line-height: 1.55;
    }
    .instrumento-evaluador {
      margin-top: auto;
      font-size: 12px;
      color: var(--texto-suave);
      background: var(--arena);
      border-radius: 6px;
      padding: 8px 10px;
    }
    .instrumento-evaluador strong { color: var(--azul-mar); }

    /* ─── Fases del proyecto ─────────────────────────────────────── */
    .fases-lista {
      display: flex;
      flex-direction: column;
      gap: 0;
    }
    .fase {
      display: flex;
      gap: 20px;
      position: relative;
    }
    .fase-linea {
      display: flex;
      flex-direction: column;
      align-items: center;
      flex-shrink: 0;
    }
    .fase-circulo {
      width: 36px; height: 36px;
      border-radius: 50%;
      background: var(--azul-mar);
      color: #fff;
      font-weight: 700;
      font-size: 14px;
      display: flex; align-items: center; justify-content: center;
      flex-shrink: 0;
      z-index: 1;
    }
    .fase-conector {
      width: 2px;
      flex: 1;
      min-height: 20px;
      background: var(--arena-oscura);
    }
    .fase:last-child .fase-conector { display: none; }
    .fase-cuerpo {
      padding-bottom: 28px;
      flex: 1;
    }
    .fase-cuerpo h3 {
      font-size: 15px;
      font-weight: 600;
      color: var(--azul-mar);
      margin-top: 5px;
      margin-bottom: 4px;
    }
    .fase-semanas {
      display: inline-block;
      font-size: 11px;
      font-weight: 600;
      letter-spacing: .08em;
      text-transform: uppercase;
      color: var(--turquesa);
      margin-bottom: 8px;
    }
    .fase-cuerpo p { font-size: 14px; color: var(--texto-suave); }

    /* ─── Nota técnica ───────────────────────────────────────────── */
    .nota-tecnica {
      background: var(--acento-claro);
      border: 1px solid #f0d0a0;
      border-radius: var(--radio);
      padding: 18px 22px;
      display: flex;
      gap: 14px;
      align-items: flex-start;
    }
    .nota-tecnica-icono { flex-shrink: 0; margin-top: 2px; }
    .nota-tecnica p { font-size: 14px; color: #6b4a1e; margin: 0; }
    .nota-tecnica strong { color: #4a2f08; }

    /* ─── Pie ────────────────────────────────────────────────────── */
    .pie {
      text-align: center;
      font-size: 12px;
      color: var(--texto-suave);
      border-top: 1px solid var(--arena-oscura);
      padding: 24px 20px;
      margin-top: 16px;
    }

    /* ─── Responsive ─────────────────────────────────────────────── */
    @media (max-width: 600px) {
      .cabecera { padding: 32px 20px 28px; }
