      color: var(--blanco);
      padding: 56px 40px 48px;
      position: relative;
      overflow: hidden;
      text-align: center;
    }
    .cabecera::before {
      content: '';
      position: absolute;
      inset: 0;
      background: radial-gradient(ellipse 80% 60% at 50% 110%, rgba(0,168,157,.18) 0%, transparent 70%);
      pointer-events: none;
    }
    /* Olas decorativas */
    .cabecera::after {
      content: '';
      position: absolute;
      bottom: -1px; left: 0; right: 0;
      height: 40px;
      background: var(--arena);
      clip-path: ellipse(55% 100% at 50% 100%);
    }

    .etiqueta {
      display: inline-block;
      font-size: 11px;
      font-weight: 600;
      letter-spacing: .14em;
