      border: 1px solid rgba(0,168,157,.5);
      border-radius: 40px;
      padding: 4px 16px;
      margin-bottom: 22px;
    }
    .cabecera h1 {
      font-family: var(--fuente-t);
      font-size: clamp(28px, 4.5vw, 42px);
      font-weight: 700;
      line-height: 1.15;
      margin-bottom: 12px;
      position: relative;
    }
    .cabecera-sub {
      font-size: 15px;
      font-style: italic;
      color: rgba(255,255,255,.65);
      position: relative;
    }

    /* ── Contenido ────────────────────────────────────────────── */
    .contenido {
