      margin: 0 auto;
      padding: 56px 24px 72px;
      flex: 1;
    }

    /* ── Tarjeta autora ───────────────────────────────────────── */
    .tarjeta-autora {
      background: var(--blanco);
      border-radius: var(--radio-lg);
